return await space.current.renderWidget({
  id: "starter-widget",
  name: "Analog Clock",
  cols: 4,
  rows: 4,
  renderer: async (parent) => {
    const tick = () => {
      const now = new Date()
      const s = now.getSeconds()
      const m = now.getMinutes() + s / 60
      const h = (now.getHours() % 12) + m / 60

      const toAngle = (value, max) => (value / max) * 360 - 90
      const hourAngle = toAngle(h, 12)
      const minAngle = toAngle(m, 60)
      const secAngle = toAngle(s, 60)

      parent.innerHTML = `
        <div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;background:#0f172a;color:#e2e8f0;font-family:sans-serif;">
          <div style="position:relative;width:170px;height:170px;border:6px solid #cbd5e1;border-radius:50%;background:#111827;box-shadow:0 0 0 4px #334155 inset;">
            ${Array.from({ length: 12 }, (_, i) => {
              const angle = (i / 12) * 360
              const rad = (angle - 90) * Math.PI / 180
              const x = 85 + Math.cos(rad) * 70
              const y = 85 + Math.sin(rad) * 70
              return `<div style="position:absolute;left:${x - 8}px;top:${y - 8}px;width:16px;height:16px;display:flex;align-items:center;justify-content:center;font-size:12px;color:#e2e8f0;">${i + 1}</div>`
            }).join("")}
            <div style="position:absolute;left:50%;top:50%;width:6px;height:50px;background:#f8fafc;border-radius:3px;transform-origin:bottom center;transform:translate(-50%,-100%) rotate(${hourAngle}deg);"></div>
            <div style="position:absolute;left:50%;top:50%;width:4px;height:68px;background:#38bdf8;border-radius:2px;transform-origin:bottom center;transform:translate(-50%,-100%) rotate(${minAngle}deg);"></div>
            <div style="position:absolute;left:50%;top:50%;width:2px;height:78px;background:#f87171;border-radius:2px;transform-origin:bottom center;transform:translate(-50%,-100%) rotate(${secAngle}deg);"></div>
            <div style="position:absolute;left:50%;top:50%;width:12px;height:12px;background:#f8fafc;border-radius:50%;transform:translate(-50%,-50%);"></div>
          </div>
        </div>
      `
    }

    tick()
    setInterval(tick, 1000)
  }
})

