return await space.current.renderWidget({
  id: "quote-board",
  name: "Quotes",
  cols: 6,
  rows: 5,
  renderer: async (parent) => {
    parent.innerHTML = `
      <div style="padding:16px;font:16px/1.5 system-ui">
        <div id="quote-text" style="font-size:20px;margin-bottom:12px;">Loading quote...</div>
        <div id="quote-author" style="opacity:.7;"></div>
        <button id="quote-refresh" style="margin-top:16px;">New quote</button>
      </div>
    `

    const quoteText = parent.querySelector("#quote-text")
    const quoteAuthor = parent.querySelector("#quote-author")
    const refreshBtn = parent.querySelector("#quote-refresh")

    const loadQuote = async () => {
      quoteText.textContent = "Loading quote..."
      quoteAuthor.textContent = ""
      try {
        const res = await fetch("https://api.quotable.io/random")
        if (!res.ok) throw new Error(`HTTP ${res.status}`)
        const data = await res.json()
        quoteText.textContent = `“${data.content}”`
        quoteAuthor.textContent = data.author ? `— ${data.author}` : ""
      } catch (err) {
        quoteText.textContent = "Failed to load quote."
        quoteAuthor.textContent = String(err)
      }
    }

    refreshBtn.addEventListener("click", loadQuote)
    await loadQuote()
  }
})

