return await space.current.patchWidget("snake-game", async (parent, state, utils) => {
  // If the framework/source already has the current widget contract, this patch can be adapted
  // by the runtime to preserve existing behavior. Replace the rendering logic with smooth
  // interpolation between grid positions for the snake/caterpillar effect.
  parent.innerHTML = `
    <style>
      .snake-wrap { position: relative; width: 100%; height: 100%; overflow: hidden; }
      canvas { width: 100%; height: 100%; display: block; image-rendering: auto; }
    </style>
    <div class="snake-wrap">
      <canvas id="snake-canvas"></canvas>
    </div>
  `

  const canvas = parent.querySelector("#snake-canvas")
  const ctx = canvas.getContext("2d")

  const resize = () => {
    const dpr = Math.max(1, window.devicePixelRatio || 1)
    const rect = parent.getBoundingClientRect()
    canvas.width = Math.max(1, Math.floor(rect.width * dpr))
    canvas.height = Math.max(1, Math.floor(rect.height * dpr))
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0)
  }

  const lerp = (a, b, t) => a + (b - a) * t

  const render = () => {
    const w = parent.clientWidth
    const h = parent.clientHeight
    ctx.clearRect(0, 0, w, h)

    const grid = state.gridSize || 20
    const cell = Math.min(w, h) / grid
    const snake = state.snake || []
    const progress = Math.max(0, Math.min(1, state.moveProgress ?? 1))

    // background
    ctx.fillStyle = "#0b1220"
    ctx.fillRect(0, 0, w, h)

    // smooth snake body using interpolated positions
    snake.forEach((segment, i) => {
      const prev = segment.prev || segment
      const curr = segment.curr || segment
      const x = lerp(prev.x, curr.x, progress) * cell + cell / 2
      const y = lerp(prev.y, curr.y, progress) * cell + cell / 2
      const r = Math.max(2, cell * (i === 0 ? 0.42 : 0.38))

      const grad = ctx.createRadialGradient(x - r * 0.25, y - r * 0.25, r * 0.2, x, y, r)
      grad.addColorStop(0, i === 0 ? "#9effb4" : "#55d17a")
      grad.addColorStop(1, i === 0 ? "#2fbf5f" : "#188a43")
      ctx.fillStyle = grad

      ctx.beginPath()
      ctx.arc(x, y, r, 0, Math.PI * 2)
      ctx.fill()
    })
  }

  const tick = () => {
    render()
    requestAnimationFrame(tick)
  }

  resize()
  window.addEventListener("resize", resize)
  tick()
})

