return await space.current.renderWidget({
  id: "snake-game",
  name: "snake-game",
  renderer: async (parent) => {
    const canvas = document.createElement("canvas")
    canvas.width = 400
    canvas.height = 400
    canvas.style.border = "1px solid #333"
    parent.innerHTML = ""
    parent.appendChild(canvas)

    const ctx = canvas.getContext("2d")
    const grid = 20
    const cols = canvas.width / grid
    const rows = canvas.height / grid

    let snake = [{ x: 10, y: 10 }]
    let nextSnake = snake.map(p => ({ ...p }))
    let direction = { x: 1, y: 0 }
    let nextDirection = { x: 1, y: 0 }
    let food = { x: 15, y: 10 }
    let score = 0
    let alive = true
    let lastMove = performance.now()
    const moveDuration = 120

    function randInt(max) {
      return Math.floor(Math.random() * max)
    }

    function spawnFood() {
      while (true) {
        const p = { x: randInt(cols), y: randInt(rows) }
        if (!snake.some(s => s.x === p.x && s.y === p.y)) return p
      }
    }

    function same(a, b) {
      return a.x === b.x && a.y === b.y
    }

    function step() {
      direction = nextDirection
      const head = { x: snake[0].x + direction.x, y: snake[0].y + direction.y }

      if (head.x < 0 || head.x >= cols || head.y < 0 || head.y >= rows || snake.some((s, i) => i < snake.length - 1 && same(s, head))) {
        alive = false
        return
      }

      snake = [head, ...snake]
      if (same(head, food)) {
        score++
        food = spawnFood()
      } else {
        snake.pop()
      }
      nextSnake = snake.map(p => ({ ...p }))
      lastMove = performance.now()
    }

    function drawPart(x, y, size, color, radius = 6) {
      ctx.fillStyle = color
      ctx.beginPath()
      ctx.roundRect(x, y, size, size, radius)
      ctx.fill()
    }

    function draw() {
      const now = performance.now()
      const t = Math.min(1, (now - lastMove) / moveDuration)
      const eased = t * t * (3 - 2 * t)

      ctx.clearRect(0, 0, canvas.width, canvas.height)
      ctx.fillStyle = "#111"
      ctx.fillRect(0, 0, canvas.width, canvas.height)

      const head = snake[0]
      const prevHead = {
        x: head.x - direction.x,
        y: head.y - direction.y
      }

      for (let y = 0; y < rows; y++) {
        for (let x = 0; x < cols; x++) {
          if ((x + y) % 2 === 0) {
            ctx.fillStyle = "#151515"
            ctx.fillRect(x * grid, y * grid, grid, grid)
          }
        }
      }

      ctx.fillStyle = "#ff4d4d"
      ctx.beginPath()
      ctx.arc(food.x * grid + grid / 2, food.y * grid + grid / 2, grid * 0.35, 0, Math.PI * 2)
      ctx.fill()

      for (let i = nextSnake.length - 1; i >= 0; i--) {
        const curr = nextSnake[i]
        const prev = snake[i] ? snake[i] : curr
        const px = (i === 0 ? prevHead.x : curr.x) * grid
        const py = (i === 0 ? prevHead.y : curr.y) * grid
        const cx = curr.x * grid
        const cy = curr.y * grid
        const x = px + (cx - px) * eased
        const y = py + (cy - py) * eased
        const shrink = i === 0 ? 0.12 : 0.18
        drawPart(x + grid * shrink, y + grid * shrink, grid * (1 - shrink * 2), i === 0 ? "#7CFC90" : "#3cbf62", 6)
      }

      ctx.fillStyle = "#fff"
      ctx.font = "16px sans-serif"
      ctx.fillText(`Score: ${score}`, 10, 20)

      if (!alive) {
        ctx.fillStyle = "rgba(0,0,0,0.55)"
        ctx.fillRect(0, 0, canvas.width, canvas.height)
        ctx.fillStyle = "#fff"
        ctx.font = "28px sans-serif"
        ctx.fillText("Game Over", 130, 190)
      } else if (now - lastMove >= moveDuration) {
        step()
      }

      requestAnimationFrame(draw)
    }

    document.addEventListener("keydown", (e) => {
      const map = {
        ArrowUp: { x: 0, y: -1 },
        ArrowDown: { x: 0, y: 1 },
        ArrowLeft: { x: -1, y: 0 },
        ArrowRight: { x: 1, y: 0 },
      }
      const d = map[e.key]
      if (!d) return
      if (d.x === -direction.x && d.y === -direction.y) return
      nextDirection = d
    })

    food = spawnFood()
    requestAnimationFrame(draw)
  }
})
